// ── Persistence multi-mode : Electron / Serveur / localStorage ────────────────
const STORAGE_KEY = "ashoid_v14_data";

// Détection de l'environnement
const IS_ELECTRON = typeof window !== "undefined" && window.electronAPI?.isElectron === true;
const IS_SERVER   = typeof window !== "undefined" && window.location.protocol !== "file:" && window.location.hostname !== "localhost" && !IS_ELECTRON
                    // On est sur un vrai serveur distant
                    ? true
                    : (typeof window !== "undefined" && window.location.port === "" && window.location.hostname !== "localhost");

// Merge profond avec les defaults (garantit tous les champs)
const mergeWithDefault = (saved) => ({
  ...DEFAULT,
  ...saved,
  config: { ...DEFAULT.config, ...(saved.config || {}) },
  utilisateurs: saved.utilisateurs?.length ? saved.utilisateurs : DEFAULT.utilisateurs,
  demandes_inscription: saved.demandes_inscription || [],
  demandes_cotisation:  saved.demandes_cotisation  || [],
  medias_galerie:       saved.medias_galerie        || [],
});

// ── Chargement initial (synchrone pour localStorage/Electron, async pour serveur)
const loadData = () => {
  // 1. Electron : lire depuis le fichier local (via IPC — appel async géré dans App)
  if (IS_ELECTRON) {
    // Retourne DEFAULT en attendant le chargement async
    return DEFAULT;
  }
  // 2. localStorage (dev local ou fallback)
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return DEFAULT;
    return mergeWithDefault(JSON.parse(raw));
  } catch { return DEFAULT; }
};

// ── Sauvegarde (fire-and-forget)
const saveData = (data) => {
  // 1. Electron → fichier local via IPC
  if (IS_ELECTRON && window.electronAPI) {
    window.electronAPI.writeData(JSON.stringify(data)).catch(() => {});
  }
  // 2. Serveur en ligne → POST /api/data
  else if (typeof window !== "undefined" && window.location.hostname !== "localhost" && window.location.protocol !== "file:") {
    fetch("/api/data", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(data),
    }).catch(() => {});
  }
  // 3. Toujours aussi dans localStorage (cache local / offline)
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify(data)); } catch {}
};

// ── Chargement async depuis le serveur ou Electron ──────────────────────────
const loadDataAsync = async () => {
  // Electron
  if (IS_ELECTRON && window.electronAPI) {
    const raw = await window.electronAPI.readData();
    if (raw) return mergeWithDefault(JSON.parse(raw));
    return DEFAULT;
  }
  // Serveur en ligne
  if (typeof window !== "undefined" && window.location.hostname !== "localhost" && window.location.protocol !== "file:") {
    try {
      const res = await fetch("/api/data");
      const json = await res.json();
      if (json.ok && json.data) return mergeWithDefault(json.data);
    } catch {}
  }
  // localStorage
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) return mergeWithDefault(JSON.parse(raw));
  } catch {}
  return DEFAULT;
};

// ── Utils ──────────────────────────────────────────────────────────────────────
const genId = () => Date.now() + Math.floor(Math.random() * 1000);
const today = () => new Date().toISOString().slice(0, 10);
const getSoldeNM1 = (finances, annee) => {
  const prev = finances.filter(f => (f.annee || 0) < annee);
  const rec = prev.filter(f => f.type_operation === "Recette").reduce((s, f) => s + Number(f.montant), 0);
  const dep = prev.filter(f => f.type_operation === "Dépense").reduce((s, f) => s + Number(f.montant), 0);
  return rec - dep;
};
const exportCSV = (rows, cols, filename) => {
  const h = cols.map(c => c.label).join(";");
  const b = rows.map(r => cols.map(c => String(r[c.key] ?? "").replace(/;/g, ",")).join(";")).join("\n");
  const blob = new Blob(["\uFEFF" + h + "\n" + b], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a"); a.href = url; a.download = filename + ".csv"; a.click();
  URL.revokeObjectURL(url);
};

// ── QR mini ────────────────────────────────────────────────────────────────────
const MiniQR = ({ value, size = 56 }) => {
  const h = s => s.split("").reduce((a, c) => ((a << 5) - a) + c.charCodeAt(0) | 0, 0);
  const n = Math.abs(h(value || "ASHOID"));
  const cells = []; const cols = 7; const cell = size / cols;
  for (let i = 0; i < 49; i++) cells.push(!!(n >> (i % 30) & 1));
  return (
    <svg width={size} height={size} style={{ borderRadius: 3, background: "#fff", border: "1px solid #ddd" }}>
      {cells.map((b, i) => b ? <rect key={i} x={(i % cols) * cell} y={Math.floor(i / cols) * cell} width={cell} height={cell} fill="#0F2D5C" /> : null)}
      {[[0, 0], [(cols - 2) * cell, 0], [0, (cols - 2) * cell]].map(([x, y], i) => (
        <g key={i}><rect x={x} y={y} width={cell * 2} height={cell * 2} fill="#0F2D5C" /><rect x={x + cell} y={y + cell} width={cell} height={cell} fill="#fff" /></g>
      ))}
    </svg>
  );
};

